import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import toast from 'react-hot-toast';
import { LayoutDashboard, Calendar, Activity, LogOut, Plus, User, Clock, MapPin, Trash2, ChevronRight, Heart, Bell } from 'lucide-react';

const statusColor = { pending: 'status-pending', assigned: 'status-assigned', active: 'status-active', completed: 'status-completed', cancelled: 'status-cancelled' };
const careIcon = { elderly: '👴', maternity: '🤱', childcare: '👶' };

export default function UserDashboard() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('overview');
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { fetchBookings(); }, []);

  const fetchBookings = async () => {
    try {
      const { data } = await axios.get('/bookings');
      setBookings(data);
    } catch (err) {
      toast.error('Failed to load bookings');
    } finally { setLoading(false); }
  };

  const cancelBooking = async (id) => {
    if (!window.confirm('Cancel this booking?')) return;
    try {
      await axios.delete(`/bookings/${id}`);
      toast.success('Booking cancelled');
      fetchBookings();
    } catch { toast.error('Failed to cancel'); }
  };

  const active = bookings.filter(b => ['active', 'assigned'].includes(b.status));
  const pending = bookings.filter(b => b.status === 'pending');
  const completed = bookings.filter(b => b.status === 'completed');

  const navItems = [
    { id: 'overview', icon: LayoutDashboard, label: 'Overview' },
    { id: 'bookings', icon: Calendar, label: 'My Bookings' },
    { id: 'health', icon: Activity, label: 'Health Updates' },
    { id: 'profile', icon: User, label: 'My Profile' },
  ];

  return (
    <div className="dashboard-layout">
      {/* Sidebar */}
      <aside className="sidebar">
        <div className="sidebar-logo">
          <Heart size={18} color="#0d9488" style={{ display: 'inline', marginRight: 6 }} />
          Prana Solutions
        </div>
        <nav className="sidebar-nav">
          {navItems.map(item => (
            <div key={item.id} className={`sidebar-item ${activeTab === item.id ? 'active' : ''}`} onClick={() => setActiveTab(item.id)}>
              <item.icon size={18} /> {item.label}
            </div>
          ))}
        </nav>
        <div style={{ marginTop: 'auto', paddingTop: 16, borderTop: '1px solid #f3f4f6' }}>
          <div style={{ padding: '12px 14px', marginBottom: 8 }}>
            <div style={{ fontSize: 13, fontWeight: 600, color: '#111827' }}>{user?.name}</div>
            <div style={{ fontSize: 12, color: '#9ca3af' }}>{user?.email}</div>
          </div>
          <div className="sidebar-item" onClick={() => { logout(); navigate('/'); }}>
            <LogOut size={18} /> Sign Out
          </div>
        </div>
      </aside>

      {/* Main */}
      <main className="main-content">
        {/* Overview */}
        {activeTab === 'overview' && (
          <div>
            <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
              <div>
                <h1 className="page-title">Good day, {user?.name?.split(' ')[0]}! 👋</h1>
                <p className="page-sub">Here's a summary of your care arrangements.</p>
              </div>
              <button className="btn btn-primary" onClick={() => navigate('/book')}>
                <Plus size={16} /> Book Caregiver
              </button>
            </div>

            <div className="stats-grid">
              {[
                { label: 'Total Bookings', value: bookings.length, icon: Calendar, color: '#e0f2fe', iconColor: '#0284c7' },
                { label: 'Active Care', value: active.length, icon: Activity, color: '#dcfce7', iconColor: '#16a34a' },
                { label: 'Pending', value: pending.length, icon: Clock, color: '#fef3c7', iconColor: '#d97706' },
                { label: 'Completed', value: completed.length, icon: Heart, color: '#fce7f3', iconColor: '#db2777' },
              ].map(s => (
                <div key={s.label} className="card stat-card">
                  <div className="stat-icon" style={{ background: s.color }}>
                    <s.icon size={20} color={s.iconColor} />
                  </div>
                  <div className="stat-value">{s.value}</div>
                  <div className="stat-label">{s.label}</div>
                </div>
              ))}
            </div>

            {/* Recent bookings */}
            <h2 className="section-title">Recent Bookings</h2>
            {loading ? <div style={{ textAlign: 'center', padding: 40 }}><div className="spinner" style={{ margin: '0 auto' }} /></div>
              : bookings.length === 0 ? (
                <div className="card" style={{ padding: 48, textAlign: 'center' }}>
                  <div style={{ fontSize: 48, marginBottom: 16 }}>🏥</div>
                  <h3 style={{ fontFamily: 'DM Serif Display,serif', fontSize: 22, marginBottom: 8, color: '#111827' }}>No bookings yet</h3>
                  <p style={{ color: '#6b7280', marginBottom: 24 }}>Book your first caregiver to get started.</p>
                  <button className="btn btn-primary" onClick={() => navigate('/book')}><Plus size={16} /> Book a Caregiver</button>
                </div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
                  {bookings.slice(0, 5).map(b => <BookingCard key={b._id} booking={b} onCancel={cancelBooking} onDetail={() => setActiveTab('bookings')} />)}
                  {bookings.length > 5 && (
                    <button className="btn btn-ghost" onClick={() => setActiveTab('bookings')} style={{ alignSelf: 'center' }}>
                      View all {bookings.length} bookings <ChevronRight size={16} />
                    </button>
                  )}
                </div>
              )}
          </div>
        )}

        {/* Bookings tab */}
        {activeTab === 'bookings' && (
          <div>
            <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                <h1 className="page-title">My Bookings</h1>
                <p className="page-sub">{bookings.length} total booking{bookings.length !== 1 ? 's' : ''}</p>
              </div>
              <button className="btn btn-primary" onClick={() => navigate('/book')}><Plus size={16} /> New Booking</button>
            </div>
            {loading ? <div style={{ textAlign: 'center', padding: 40 }}><div className="spinner" style={{ margin: '0 auto' }} /></div>
              : bookings.length === 0 ? (
                <div className="empty-state"><Calendar size={48} /><h3>No bookings yet</h3><p>Create your first booking to see it here.</p></div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
                  {bookings.map(b => <BookingCard key={b._id} booking={b} onCancel={cancelBooking} expanded />)}
                </div>
              )}
          </div>
        )}

        {/* Health Updates */}
        {activeTab === 'health' && (
          <div>
            <div className="page-header">
              <h1 className="page-title">Health Updates</h1>
              <p className="page-sub">Latest updates from your caregivers</p>
            </div>
            {bookings.flatMap(b => (b.healthUpdates || []).map(u => ({ ...u, booking: b }))).length === 0 ? (
              <div className="empty-state"><Bell size={48} /><h3>No updates yet</h3><p>Health updates from caregivers will appear here.</p></div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                {bookings.flatMap(b => (b.healthUpdates || []).map(u => (
                  <div key={u._id} className="card" style={{ padding: 20, display: 'flex', gap: 16 }}>
                    <div style={{ width: 40, height: 40, borderRadius: '50%', background: '#ccfbf1', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                      <Activity size={18} color="#0f766e" />
                    </div>
                    <div>
                      <div style={{ fontSize: 13, color: '#9ca3af', marginBottom: 4 }}>{b.patient?.name} · {new Date(u.timestamp).toLocaleString()}</div>
                      <div style={{ fontSize: 15, color: '#111827' }}>{u.message}</div>
                    </div>
                  </div>
                )))}
              </div>
            )}
          </div>
        )}

        {/* Profile */}
        {activeTab === 'profile' && (
          <div>
            <div className="page-header">
              <h1 className="page-title">My Profile</h1>
              <p className="page-sub">Manage your account information</p>
            </div>
            <div className="card" style={{ padding: 32, maxWidth: 540 }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 20, marginBottom: 32 }}>
                <div style={{ width: 64, height: 64, borderRadius: '50%', background: '#ccfbf1', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 24, fontWeight: 700, color: '#0f766e' }}>
                  {user?.name?.charAt(0)}
                </div>
                <div>
                  <div style={{ fontSize: 20, fontWeight: 700, color: '#111827' }}>{user?.name}</div>
                  <div style={{ fontSize: 14, color: '#6b7280' }}>{user?.email}</div>
                  <span className="badge badge-teal" style={{ marginTop: 6 }}>Family Member</span>
                </div>
              </div>
              {[
                { label: 'Name', value: user?.name },
                { label: 'Email', value: user?.email },
                { label: 'Phone', value: user?.phone || 'Not set' },
                { label: 'Role', value: 'User / Family' },
                { label: 'Member Since', value: new Date(user?.createdAt || Date.now()).toLocaleDateString('en-IN', { year: 'numeric', month: 'long' }) },
              ].map(f => (
                <div key={f.label} style={{ display: 'flex', justifyContent: 'space-between', padding: '14px 0', borderBottom: '1px solid #f3f4f6', fontSize: 14 }}>
                  <span style={{ color: '#9ca3af', fontWeight: 600 }}>{f.label}</span>
                  <span style={{ color: '#111827', fontWeight: 500 }}>{f.value}</span>
                </div>
              ))}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

function BookingCard({ booking: b, onCancel, expanded }) {
  return (
    <div className="card" style={{ padding: 24 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: 12 }}>
        <div style={{ display: 'flex', gap: 16, alignItems: 'flex-start' }}>
          <div style={{ fontSize: 32 }}>{careIcon[b.careType] || '🏥'}</div>
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 4 }}>
              <span style={{ fontSize: 16, fontWeight: 700, color: '#111827' }}>{b.patient?.name}</span>
              <span className={`badge ${statusColor[b.status]}`} style={{ fontSize: 11 }}>{b.status?.charAt(0).toUpperCase() + b.status?.slice(1)}</span>
            </div>
            <div style={{ fontSize: 13, color: '#6b7280' }}>
              {b.careType?.charAt(0).toUpperCase() + b.careType?.slice(1)} · Age {b.patient?.age} · {b.patient?.gender}
            </div>
            {expanded && (
              <>
                <div style={{ fontSize: 13, color: '#6b7280', marginTop: 6, display: 'flex', alignItems: 'center', gap: 6 }}>
                  <Clock size={13} /> {b.schedule?.timeSlot} · {b.schedule?.duration}
                </div>
                <div style={{ fontSize: 13, color: '#6b7280', marginTop: 3, display: 'flex', alignItems: 'center', gap: 6 }}>
                  <MapPin size={13} /> {b.location?.address}, {b.location?.city}
                </div>
                {b.caregiver?.user && (
                  <div style={{ marginTop: 10, padding: '10px 14px', background: '#f0fdfa', borderRadius: 10, fontSize: 13 }}>
                    <span style={{ fontWeight: 600, color: '#0f766e' }}>Caregiver: </span>
                    <span style={{ color: '#374151' }}>{b.caregiver.user.name} · {b.caregiver.user.phone}</span>
                  </div>
                )}
              </>
            )}
          </div>
        </div>
        <div style={{ display: 'flex', gap: 8 }}>
          {['pending', 'assigned'].includes(b.status) && (
            <button className="btn btn-danger btn-sm" onClick={() => onCancel(b._id)}><Trash2 size={14} /> Cancel</button>
          )}
        </div>
      </div>
      <div style={{ marginTop: 14, paddingTop: 12, borderTop: '1px solid #f3f4f6', display: 'flex', justifyContent: 'space-between', fontSize: 12, color: '#9ca3af' }}>
        <span>Booked: {new Date(b.createdAt).toLocaleDateString('en-IN')}</span>
        {b.schedule?.startDate && <span>Start: {new Date(b.schedule.startDate).toLocaleDateString('en-IN')}</span>}
      </div>
    </div>
  );
}
